from pathlib import Path
path=Path('MainWindow.xaml')
text=path.read_text(encoding='utf-8')
old='        <Border Grid.Row="2"\n                Background="{StaticResource BackgroundBrush}"\n                BorderBrush="{StaticResource BorderBrush}"\n                BorderThickness="0,1,0,0"\n                Padding="10,4">\n            <Grid>\n                <Grid.ColumnDefinitions>\n                    <ColumnDefinition Width="*" />\n                    <ColumnDefinition Width="Auto" />\n                </Grid.ColumnDefinitions>\n\n                <!-- Left: scan status message -->\n                <TextBlock x:Name="StatusText" Grid.Column="0"\n                           Text="Ready" FontSize="11"\n                           Foreground="{StaticResource TextBrush}"\n                           VerticalAlignment="Center" />\n\n                <!-- Right: version number as a clickable link to the repo -->\n                <TextBlock Grid.Column="1" FontSize="10"\n                           VerticalAlignment="Center"\n                           Foreground="{StaticResource HeaderTextBrush}">\n                    <Hyperlink x:Name="VersionLink"\n                               NavigateUri="https://github.com/micahp2/NetworkScanner"\n                               RequestNavigate="VersionLink_RequestNavigate"\n                               Foreground="{StaticResource HeaderTextBrush}">\n                        <Run x:Name="VersionText" Text="v1.0.0" />\n                    </Hyperlink>\n                </TextBlock>\n            </Grid>\n        </Border>\n'
new='        <Border Grid.Row="2"\n                Background="{StaticResource BackgroundBrush}"\n                BorderBrush="{StaticResource BorderBrush}"\n                BorderThickness="0,1,0,0"\n                Padding="10,4">\n            <Grid>\n                <Grid.ColumnDefinitions>\n                    <ColumnDefinition Width="*" />\n                    <ColumnDefinition Width="Auto" />\n                </Grid.ColumnDefinitions>\n\n                <!-- Left: scan status message + theme indicator -->\n                <StackPanel Grid.Column="0" Orientation="Horizontal" VerticalAlignment="Center">\n                    <TextBlock x:Name="StatusText"\n                               Text="Ready" FontSize="11"\n                               Foreground="{StaticResource TextBrush}"\n                               VerticalAlignment="Center" />\n                    <TextBlock x:Name="ThemeIndicator"\n                               Text="Theme: Light" FontSize="10"\n                               Margin="12,0,0,0"\n                               Foreground="{StaticResource HeaderTextBrush}"\n                               VerticalAlignment="Center" />\n                </StackPanel>\n\n                <!-- Right: version number as a clickable link to the repo -->\n                <TextBlock Grid.Column="1" FontSize="10"\n                           VerticalAlignment="Center"\n                           Foreground="{StaticResource HeaderTextBrush}">\n                    <Hyperlink x:Name="VersionLink"\n                               NavigateUri="https://github.com/micahp2/NetworkScanner"\n                               RequestNavigate="VersionLink_RequestNavigate"\n                               Foreground="{StaticResource HeaderTextBrush}">\n                        <Run x:Name="VersionText" Text="v1.0.0" />\n                    </Hyperlink>\n                </TextBlock>\n            </Grid>\n        </Border>\n'
if old not in text:
    raise SystemExit('status block not found')
path.write_text(text.replace(old,new,1),encoding='utf-8')
